                                    if let Some(Value::VmObject(arr_ctor)) = self.globals.get("Array")
                                        && let Some(Value::VmObject(proto)) = arr_ctor.borrow().get("prototype").cloned()
                                        && proto.borrow().get("@@sym:1").is_some()
                                    {
                                        found = true;
                                    }
